command.text:
        /* <flatten type="Javascript"> */
var f = this, d1 = f.getItemValue('ngay_hl'), d2 = f.getItemValue('ngay_hl2'), v = f._language == 'v', e;
if (d2 != null && d1 > d2) {
  f._errorObject = f.getItem('ngay_hl2');
  e = (v ? 'Trường <span class="Highlight">Ngày hiệu lực từ</span> phải nhỏ hơn hoặc bằng <span class="Highlight">Ngày hiệu lực đến</span>.' : '<span class="Highlight">Effective date from</span> must be less than <span class="Highlight">effective date to</span>.');
  f._checked = false;
}
if (!f._checked) $message.show(e, String.format('$find(\'{0}\')._errorObject.focus()', f.get_id()));
/* </flatten> */

script.text:
      /* <flatten type="Javascript"> */
function init$FormApprovingOfficers(f) {
  var g = f.grid;
  f.setItemValue('loai_duyet', g._approvalType);
  if (f.getItemValue('user_id') == 0) {f.setItemValues('user_id, name, comment%l', [g._userID, g._userName, g._userComment]);}
  f.setReferenceKeyFilter('ma_quyen', 'name');
  if (f._action == 'New') f.setItemValue('ngay_hl', new Date());
}
function active$FormApprovingOfficers$(f) {f.add_onResponseComplete(on$FormApprovingOfficers$ResponseComplete);}
function close$FormApprovingOfficers$(f) {try {f.remove_onResponseComplete(on$FormApprovingOfficers$ResponseComplete);} catch (ex) {}}
function onChange$FormApprovingOfficers$UserID(f) {f.request('GetUserID', 'SetUserID', ['name']);}
function on$FormApprovingOfficers$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'SetUserID':
      f.setItemValue('user_id', result[0].Value);
      break;
    default:
      break;
  }
}
function setObjectFormHidden(f, c, b) {if (b) {$common.setVisible(f.getItem(c).parentNode.parentNode.parentNode, false);}}
/* </flatten> */
